16	package io.helidon.dbclient.jdbc;
17	
18	import java.sql.PreparedStatement;
19	import java.sql.ResultSet;
20	import java.sql.SQLException;
21	import java.util.Optional;
22	import java.util.concurrent.CompletableFuture;
23	
24	import io.helidon.dbclient.DbClientServiceContext;
25	import io.helidon.dbclient.DbRow;
26	import io.helidon.dbclient.DbStatementException;
27	import io.helidon.dbclient.DbStatementGet;
28	import io.helidon.dbclient.DbStatementType;
29	
30	/**
31	 * JDBC implementation of {@link DbStatementGet}.
32	 */
33	class JdbcStatementGet extends JdbcStatement<DbStatementGet> implements DbStatementGet {
34	
35	    /**
36	     * Create a new instance.
37	     *
38	     * @param connectionPool connection pool
39	     * @param context        execution context
40	     */
41	    JdbcStatementGet(JdbcConnectionPool connectionPool, JdbcExecuteContext context) {
42	        super(connectionPool, context);
43	    }
44	
45	    @Override
46	    public DbStatementType statementType() {
47	        return DbStatementType.GET;
48	    }
49	
50	    @Override
51	    public Optional<DbRow> execute() {
52	        return doExecute((future, context) -> {
53	            try {
54	                return doExecute(this, future, context);
55	            } finally {
56	                closeConnection();
57	            }
58	        });
59	    }
60	
61	    /**
62	     * Execute the given statement.
63	     *
64	     * @param dbStmt  db statement
65	     * @param future  query future
66	     * @param context service context
67	     * @return query result
68	     */
69	    static Optional<DbRow> doExecute(JdbcStatement<? extends DbStatementGet> dbStmt,
70	                                     CompletableFuture<Long> future,
71	                                     DbClientServiceContext context) {
72	
73	        try (PreparedStatement statement = dbStmt.prepareStatement(context);
74	             ResultSet rs = statement.executeQuery()) {
75	            if (rs.next()) {
76	                Optional<DbRow> result = Optional.of(JdbcRow.create(rs, dbStmt.context()));
77	                future.complete(1L);
78	                return result;
79	            } else {
80	                future.complete(0L);
81	                return Optional.empty();
82	            }
83	        } catch (SQLException ex) {
84	            throw new DbStatementException("Failed to execute Statement", dbStmt.context().statement(), ex);
85	        }
86	    }
87	}
