149	        MongoCollection<Document> mc = db().getCollection(stmt.getCollection());
150	        InsertOneResult result = mc.insertOne(stmt.getValue());
151	        if (returnGeneratedKeys && result.wasAcknowledged()) {
152	            BsonValue insertedId = result.getInsertedId();
153	            if (insertedId != null) {
154	                return DbResultDml.create(
155	                        Stream.of(
156	                                new MongoDbRow(
