30	
31	import com.mongodb.client.MongoDatabase;
32	import jakarta.json.Json;
33	import org.bson.Document;
34	
35	import static io.helidon.dbclient.mongodb.MongoDbStatement.MongoOperation.COMMAND;
36	import static io.helidon.dbclient.mongodb.MongoDbStatement.MongoOperation.DELETE;
37	import static io.helidon.dbclient.mongodb.MongoDbStatement.MongoOperation.INSERT;
38	import static io.helidon.dbclient.mongodb.MongoDbStatement.MongoOperation.QUERY;
39	import static io.helidon.dbclient.mongodb.MongoDbStatement.MongoOperation.UPDATE;
40	
41	/**
42	 * Common MongoDB statement builder.
43	 *
44	 * @param <S> type of subclass
45	 */
46	abstract class MongoDbStatement<S extends DbStatement<S>> extends DbStatementBase<S> {
47	
48	    /**
49	     * Empty JSON object.
50	     */
51	    static final Document EMPTY = Document.parse(Json.createObjectBuilder().build().toString());
52	
53	    /**
54	     * Operation JSON parameter name.
55	     */
56	    protected static final String JSON_OPERATION = "operation";
57	
58	    /**
59	     * Collection JSON parameter name.
60	     */
61	    protected static final String JSON_COLLECTION = "collection";
62	
63	    /**
64	     * Query JSON parameter name.
65	     */
66	    protected static final String JSON_QUERY = "query";
67	
68	    /**
69	     * Value JSON parameter name.
70	     */
71	    protected static final String JSON_VALUE = "value";
72	
73	    /**
74	     * Projection JSON parameter name: Defines projection to restrict returned fields.
75	     */
76	    protected static final String JSON_PROJECTION = "projection";
77	
78	    private final MongoDatabase db;
79	
80	    /**
81	     * Create a new instance.
82	     *
83	     * @param db      MongoDb instance
84	     * @param context context
85	     */
86	    MongoDbStatement(MongoDatabase db, DbExecuteContext context) {
87	        super(context);
88	        this.db = db;
89	    }
90	
91	    /**
92	     * Get the mongo db instance.
93	     *
94	     * @return MongoDatabase
95	     */
96	    MongoDatabase db() {
97	        return db;
98	    }
99	
100	    /**
101	     * Prepare the statement string.
102	     *
103	     * @return prepared statement string
104	     */
105	    String prepareStatement(DbClientServiceContext serviceContext) {
106	        String statement = serviceContext.statement();
107	        DbStatementParameters stmtParams = serviceContext.statementParameters();
108	        if (stmtParams instanceof DbIndexedStatementParameters indexed) {
109	            List<Object> params = indexed.parameters();
110	            return StatementParsers.indexedParser(statement, params).convert();
111	        } else if (stmtParams instanceof DbNamedStatementParameters named) {
112	            Map<String, Object> params = named.parameters();
113	            return StatementParsers.namedParser(statement, params).convert();
114	        }
115	        return statement;
116	    }
117	
118	    /**
119	     * Mongo operation enumeration.
120	     */
121	    enum MongoOperation {
122	        QUERY("query", "find", "select"),
123	        INSERT("insert"),
124	        UPDATE("update"),
125	        DELETE("delete"),
126	        // Database command not related to a specific collection
127	        // Only executable using generic statement
128	        COMMAND("command");
129	
130	        private static final Map<String, MongoOperation> NAME_TO_OPERATION = new HashMap<>();
131	
132	        static {
133	            for (MongoOperation value : MongoOperation.values()) {
134	                for (String name : value.names) {
135	                    NAME_TO_OPERATION.put(name.toLowerCase(), value);
136	                }
137	            }
138	        }
139	
140	        static MongoOperation operationByName(String name) {
141	            if (name == null) {
142	                return null;
143	            }
144	            return NAME_TO_OPERATION.get(name.toLowerCase());
145	        }
146	
147	        private final String[] names;
148	
149	        MongoOperation(String... names) {
150	            this.names = names;
151	        }
152	    }
153	
154	    /**
155	     * MongoDB statement.
156	     */
157	    static class MongoStatement {
158	
159	        private static Document readStmt(String preparedStmt) {
160	            return Document.parse(preparedStmt);
161	        }
162	
163	        private final String preparedStmt;
164	        private final MongoOperation operation;
165	        private final String collection;
166	        private final Document query;
167	        private final Document value;
168	        private final Document projection;
169	
170	        /**
171	         * Create a new instance.
172	         *
173	         * @param stmtType     statement type
174	         * @param preparedStmt prepared statement
175	         */
176	        MongoStatement(DbStatementType stmtType, String preparedStmt) {
177	            this.preparedStmt = preparedStmt;
178	            Document jsonStmt = readStmt(preparedStmt);
179	
180	            MongoOperation operation;
181	            if (jsonStmt.containsKey(JSON_OPERATION)) {
182	                operation = MongoOperation.operationByName(jsonStmt.getString(JSON_OPERATION));
183	                // make sure we have alignment between statement type and operation
184	                switch (stmtType) {
185	                    case QUERY, GET -> validateOperation(stmtType, operation, QUERY);
186	                    case INSERT -> validateOperation(stmtType, operation, INSERT);
187	                    case UPDATE -> validateOperation(stmtType, operation, UPDATE);
188	                    case DELETE -> validateOperation(stmtType, operation, DELETE);
189	                    case DML -> validateOperation(stmtType, operation, INSERT, UPDATE, DELETE);
190	                    case COMMAND -> validateOperation(stmtType, operation, COMMAND);
191	                    default -> throw new IllegalStateException(
192	                            "Operation type is not defined in statement, and cannot be inferred from statement type: "
193	                                    + stmtType);
194	                }
195	            } else {
196	                operation = switch (stmtType) {
197	                    case QUERY, GET -> QUERY;
198	                    case INSERT -> INSERT;
199	                    case UPDATE -> UPDATE;
200	                    case DELETE -> DELETE;
201	                    case COMMAND -> COMMAND;
202	                    default -> throw new IllegalStateException(
203	                            "Operation type is not defined in statement, and cannot be inferred from statement type: "
204	                                    + stmtType);
205	                };
206	            }
207	            this.operation = operation;
208	            this.collection = jsonStmt.getString(JSON_COLLECTION);
209	            this.value = jsonStmt.get(JSON_VALUE, Document.class);
210	            this.query = jsonStmt.get(JSON_QUERY, Document.class);
211	            this.projection = jsonStmt.get(JSON_PROJECTION, Document.class);
212	        }
213	
214	        private static void validateOperation(DbStatementType dbStatementType,
215	                                              MongoOperation actual,
216	                                              MongoOperation... expected) {
217	
218	            // PERF: time complexity of this check is terrible
219	            for (MongoOperation operation : expected) {
220	                if (actual == operation) {
221	                    return;
222	                }
223	            }
224	
225	            throw new IllegalStateException("Statement type is "
226	                    + dbStatementType
227	                    + ", yet operation in statement is: "
228	                    + actual);
229	        }
230	
231	        MongoOperation getOperation() {
232	            return operation;
233	        }
234	
235	        String getCollection() {
236	            return collection;
237	        }
238	
239	        Document getQuery() {
240	            return query != null ? query : EMPTY;
241	        }
242	
243	        Document getValue() {
244	            return value;
