```java
import java.lang.reflect.Array;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Iterator;
import java.util.Map;

import io.helidon.json.JsonNull;
import io.helidon.json.JsonNumber;
import io.helidon.json.JsonString;
import io.helidon.json.JsonValue;

final class JsonSupport {
    private JsonSupport() {
    }

    static String toJson(Object input) {
        if (input == null) {
            return JsonNull.instance().toString();
        }

        if (input instanceof JsonValue json) {
            return json.toString();
        }

        if (input instanceof Map<?, ?> map) {
            return mapToJson(map);
        }

        if (input instanceof Iterable<?> iterable) {
            return iterableToJson(iterable);
        }

        if (input.getClass().isArray()) {
            return arrayToJson(input);
        }

        if (input instanceof Integer || input instanceof Short || input instanceof Byte) {
            return JsonNumber.create(((Number) input).longValue()).toString();
        }

        if (input instanceof Long longValue) {
            return JsonNumber.create(longValue).toString();
        }

        if (input instanceof Double || input instanceof Float) {
            return JsonNumber.create(((Number) input).doubleValue()).toString();
        }

        if (input instanceof BigInteger || input instanceof BigDecimal) {
            return input.toString();
        }

        if (input instanceof Boolean) {
            return input.toString();
        }

        if (input instanceof Number) {
            return input.toString();
        }

        return JsonString.create(String.valueOf(input)).toString();
    }

    private static String mapToJson(Map<?, ?> map) {
        StringBuilder result = new StringBuilder("{");
        Iterator<? extends Map.Entry<?, ?>> entries = map.entrySet().iterator();

        while (entries.hasNext()) {
            Map.Entry<?, ?> entry = entries.next();
            result.append(JsonString.create(String.valueOf(entry.getKey())));
            result.append(':');
            result.append(toJson(entry.getValue()));

            if (entries.hasNext()) {
                result.append(',');
            }
        }

        return result.append('}').toString();
    }

    private static String iterableToJson(Iterable<?> iterable) {
        StringBuilder result = new StringBuilder("[");
        Iterator<?> values = iterable.iterator();

        while (values.hasNext()) {
            result.append(toJson(values.next()));

            if (values.hasNext()) {
                result.append(',');
            }
        }

        return result.append(']').toString();
    }

    private static String arrayToJson(Object array) {
        StringBuilder result = new StringBuilder("[");
        int size = Array.getLength(array);

        for (int i = 0; i < size; i++) {
            result.append(toJson(Array.get(array, i)));

            if (i + 1 < size) {
                result.append(',');
            }
        }

        return result.append(']').toString();
    }
}
```

