31	final class StatementParsers {
32	
33	    /**
34	     * Local logger instance.
35	     */
36	    private static final System.Logger LOGGER = System.getLogger(StatementParsers.class.getName());
37	
38	    /**
39	     * Create a JSON representation of a value.
40	     *
41	     * @param value value
42	     * @return JSON value
43	     */
44	    static String toJson(Object value) {
45	        if ((value instanceof Integer) || (value instanceof Short) || (value instanceof Byte)) {
46	            return Json.createValue(((Number) value).intValue()).toString();
47	        }
48	        if (value instanceof Long) {
49	            return Json.createValue((Long) value).toString();
50	        }
51	        if ((value instanceof Double) || (value instanceof Float)) {
52	            return Json.createValue(((Number) value).doubleValue()).toString();
53	        }
54	        if (value instanceof BigInteger) {
55	            return Json.createValue((BigInteger) value).toString();
56	        }
57	        if (value instanceof BigDecimal) {
58	            return Json.createValue((BigDecimal) value).toString();
59	        }
60	        if (value instanceof Boolean) {
61	            return value.toString();
62	        }
63	        // Check instanceof Number is more expensive than final types, it shall be at the end
64	        if (value instanceof Number) {
65	            return value.toString();
66	        }
67	        // String.valueOf handles null value
68	        return Json.createValue(String.valueOf(value)).toString();
69	    }
70	
71	    private StatementParsers() {
72	    }
73	
74	    static StatementParser indexedParser(String statement, List<Object> indexedParams) {
75	        return new IndexedParser(statement, indexedParams);
76	    }
77	
78	    static StatementParser namedParser(String statement, Map<String, Object> indexedParams) {
79	        return new NamedParser(statement, indexedParams);
80	    }
81	
82	    @FunctionalInterface
83	    interface StatementParser {
84	        String convert();
85	    }
86	
87	    // Slightly modified copy-paste from JDBC statement parser
88	    // Replaces "$name" named parameters with value from mappings if exists
89	    abstract static class Parser {
90	        /**
91	         * Parser ACTION to be performed.
92	         */
93	        @FunctionalInterface
94	        interface Action {
95	            void process(Parser parser);
96	        }
97	
98	        /**
99	         * States used in state machine.
100	         */
101	        enum State {
102	            STATEMENT, // Common statement
103	            STRING,    // SQL string
104	            PAR_BEG,   // After colon, expecting parameter name
105	            PARAMETER  // Processing parameter name
106	        }
107	
108	        /**
109	         * Copy character from input string to output as is.
110	         *
111	         * @param parser parser instance
112	         */
113	        static void copyChar(Parser parser) {
114	            parser.sb.append(parser.c);
115	        }
116	
117	        /**
118	         * SQL statement to be parsed.
119	         */
120	        private final String statement;
121	        /**
122	         * Target SQL statement builder.
123	         */
124	        private final StringBuilder sb;
125	
126	        /**
127	         * Character being currently processed.
128	         */
129	        private char c;
130	
131	        private Parser(String statement) {
132	            this.sb = new StringBuilder(statement.length());
133	            this.statement = statement; // temporary string storage
134	            this.c = '\0';
135	        }
136	
137	        String statement() {
138	            return statement;
139	        }
140	
141	        StringBuilder sb() {
142	            return sb;
143	        }
144	
145	        char c() {
146	            return c;
147	        }
148	
149	        void c(char newC) {
150	            c = newC;
151	        }
152	    }
153	
154	    /**
155	     * Mapping parser state machine.
156	     */
157	    static final class NamedParser implements StatementParser {
158	
159	        /**
160	         * First character of named parameter identifier.
161	         */
162	        private static final char PAR_BEG = '$';
163	
164	        /**
165	         * Parser ACTION interface.
166	         */
167	        private interface Action extends Consumer<NamedParser> {
168	        }
169	
170	        /**
171	         * States used in state machine.
172	         */
173	        enum State {
174	            STATEMENT, // Common statement
175	            STRING,    // SQL string
176	            PAR_BEG,   // After colon, expecting parameter name
177	            PARAMETER  // Processing parameter name
178	        }
179	
180	        /**
181	         * Character classes used in state machine.
182	         */
183	        private enum CharClass {
184	            LETTER, // Letter
185	            NUMBER, // Number
186	            QUOTE,  // Double quote, begins/ends string in JSON
187	            COLON,  // Colon, not a parameter when part of the sequence
188	            DOLLAR, // Dollar sign, begins named parameter
189	            OTHER;  // Other character
190	
191	            // This is far from optimal code, but direct translation table would be too large for Java char
192	            private static CharClass charClass(char c) {
193	                return switch (c) {
194	                    case '"' -> QUOTE;
195	                    case PAR_BEG -> DOLLAR;
196	                    case ':' -> COLON;
197	                    default -> Character.isLetter(c)
198	                            ? LETTER
199	                            : (Character.isDigit(c) ? NUMBER : OTHER);
200	                };
201	            }
202	
203	        }
204	
205	        /**
206	         * States TRANSITION table.
207	         */
208	        private static final State[][] TRANSITION = {
209	                // Transitions from STATEMENT state
210	                {
211	                        // LETTER: regular part of the statement, keep processing it
212	                        State.STATEMENT,
213	                        // NUMBER: regular part of the statement, keep processing it
214	                        State.STATEMENT,
215	                        // QUOTE: beginning of JSON string processing, switch to STRING state
216	                        State.STRING,
217	                        // COLON: regular part of the statement, keep processing it
218	                        State.STATEMENT,
219	                        // DOLLAR: possible beginning of named parameter, switch to PAR_BEG state
220	                        State.PAR_BEG,
221	                        // OTHER: regular part of the statement, keep processing it
222	                        State.STATEMENT
223	                },
224	                // Transitions from STRING state
225	                {
226	                        //LETTER: regular part of the JSON string, keep processing it
227	                        State.STRING,
228	                        // NUMBER: regular part of the JSON string, keep processing it
229	                        State.STRING,
230	                        // QUOTE: end of JSON string processing, go back to STATEMENT state
231	                        State.STATEMENT,
232	                        // COLON: regular part of the JSON string, keep processing it
233	                        State.STRING,
234	                        // DOLLAR: regular part of the JSON string, keep processing it
235	                        State.STRING,
236	                        // OTHER: regular part of the JSON string, keep processing it
237	                        State.STRING
238	                },
239	                // Transitions from PAR_BEG state
240	                {
241	                        // LETTER: first character of named parameter, switch to PARAMETER state
242	                        State.PARAMETER,
243	                        // NUMBER: can't be first character of named parameter, go back to STATEMENT state
244	                        State.STATEMENT,
245	                        // QUOTE: not a named parameter but beginning of JSON string processing, switch to STRING state
246	                        State.STRING,
247	                        // COLON: can't be first character of named parameter, go back to STATEMENT state
248	                        State.STATEMENT,
249	                        // DOLLAR: not a named parameter but possible beginning of another named parameter
250	                        // retry named parameter processing
251	                        State.PAR_BEG,
252	                        // OTHER: can't be first character of named parameter, go back to STATEMENT state
253	                        State.STATEMENT
254	                },
255	                // Transitions from PARAMETER state
256	                {
257	                        // LETTER: next character of named parameter, keep processing it
258	                        State.PARAMETER,
259	                        // NUMBER: next character of named parameter, keep processing it
260	                        State.PARAMETER,
261	                        // QUOTE: end of named parameter and beginning of JSON string processing, switch to STRING state
262	                        State.STATEMENT,
263	                        // COLON: not a named parameter, colon is part of the name, go back to STATEMENT state
264	                        State.STATEMENT,
265	                        // DOLLAR: end of named parameter and possible beginning of another named parameter switch
266	                        // to PAR_BEG state
267	                        State.PAR_BEG,
268	                        // OTHER: can't be next character of named parameter, go back to STATEMENT state
269	                        State.STATEMENT
270	                }
271	        };
272	
273	
274	        /**
275	         * States TRANSITION ACTION table.
276	         */
277	        private static final Action[][] ACTION = {
278	                // Actions performed on transitions from STATEMENT state
279	                {
280	                        // LETTER: copy regular statement character to output
281	                        NamedParser::copyCurrChar,
282	                        // NUMBER: copy regular statement character to output
283	                        NamedParser::copyCurrChar,
284	                        // QUOTE: copy regular statement character to output
285	                        NamedParser::copyCurrChar,
286	                        // COLON: copy regular statement character to output
287	                        NamedParser::copyCurrChar,
288	                        // DOLLAR: store current character position
289	                        NamedParser::storeCharPos,
290	                        // OTHER: copy regular statement character to output
291	                        NamedParser::copyCurrChar
292	                },
293	                // Actions performed on transitions from STRING state
294	                {
295	                        // LETTER: copy regular statement character to output
296	                        NamedParser::copyCurrChar,
297	                        // NUMBER: copy regular statement character to output
298	                        NamedParser::copyCurrChar,
299	                        // QUOTE: copy regular statement character to output
300	                        NamedParser::copyCurrChar,
301	                        // COLON: copy regular statement character to output
302	                        NamedParser::copyCurrChar,
303	                        // DOLLAR: copy regular statement character to output
304	                        NamedParser::copyCurrChar,
305	                        // OTHER: copy regular statement character to output
306	                        NamedParser::copyCurrChar
307	                },
308	                // Actions performed on transitions from PAR_BEG state
309	                {
310	                        // LETTER: do nothing, parameter name was not finished yet
311	                        NamedParser::doNothing,
312	                        // NUMBER: copy characters from stored position up to current character to output
313	                        NamedParser::copyStoredChars,
314	                        // QUOTE: copy characters from stored position up to current character to output
315	                        NamedParser::copyStoredChars,
316	                        // COLON: copy characters from stored position up to current character to output
317	                        NamedParser::copyStoredChars,
318	                        // DOLLAR: copy characters from stored position up to current character to output
319	                        NamedParser::copyStoredCharsStoreCharPos,
320	                        // OTHER: copy characters from stored position up to current character to output
321	                        NamedParser::copyStoredChars
322	                },
323	                // Actions performed on transitions from PARAMETER state
324	                {
325	                        // LETTER: do nothing, parameter name was not finished yet
326	                        NamedParser::doNothing,
327	                        // NUMBER: do nothing, parameter name was not finished yet
328	                        NamedParser::doNothing,
329	                        // QUOTE: finish parameter processing
330	                        NamedParser::finishParamCopyCurrChar,
331	                        // COLON: copy characters from stored position up to current character to output
332	                        NamedParser::copyStoredChars,
333	                        // DOLLAR: finish parameter processing
334	                        NamedParser::finishParamStoreCharPos,
335	                        // OTHER: finish parameter processing
336	                        NamedParser::finishParamCopyCurrChar
337	                }
338	        };
339	
340	        /**
341	         * Do nothing.
342	         *
343	         * @param parser parser instance
344	         */
345	        static void doNothing(NamedParser parser) {
346	        }
347	
348	        /**
349	         * Copy current character from input string to output as is.
350	         *
351	         * @param parser parser instance
352	         */
353	        static void copyCurrChar(NamedParser parser) {
354	            parser.sb.append(parser.statement.charAt(parser.curPos));
355	        }
356	
357	        /**
358	         * Copy characters from stored position up to current character from input string to output as is.
359	         *
360	         * @param parser parser instance
361	         */
362	        static void copyStoredChars(NamedParser parser) {
363	            parser.sb.append(parser.statement, parser.paramBegPos, parser.curPos + 1);
364	        }
365	
366	        /**
367	         * Store current character position into parser instance.
368	         *
369	         * @param parser parser instance
370	         */
371	        private static void storeCharPos(NamedParser parser) {
372	            parser.paramBegPos = parser.curPos;
373	        }
374	
375	        /**
376	         * Copy characters from stored position up to previous character from input string to output as is.
377	         * Store current character position into parser instance.
378	         *
379	         * @param parser parser instance
