27	import com.mongodb.client.MongoClient;
28	import com.mongodb.client.MongoClients;
29	import com.mongodb.client.MongoDatabase;
30	
31	import static java.util.Objects.requireNonNull;
32	
33	/**
34	 * MongoDB driver handler.
35	 */
36	public class MongoDbClient extends DbClientBase implements DbClient {
37	    private final MongoClient client;
38	    private final MongoDatabase db;
39	
40	    /**
41	     * Creates an instance of MongoDB driver handler.
42	     *
43	     * @param builder builder for mongoDB database
44	     */
45	    MongoDbClient(MongoDbClientBuilder builder) {
46	        super(DbClientContext.builder()
47	                .statements(builder.statements())
48	                .dbMapperManager(builder.dbMapperManager())
49	                .mapperManager(builder.mapperManager())
50	                .clientServices(builder.clientServices())
51	                .dbType(MongoDbClientProvider.DB_TYPE)
52	                .build());
53	
54	        MongoDbClientConfig config = builder.dbConfig();
55	        ConnectionString connectionString = new ConnectionString(config.url());
56	
57	        MongoClientSettings.Builder settingsBuilder = MongoClientSettings.builder()
58	                .applyConnectionString(connectionString);
59	
60	        String dbName = connectionString.getDatabase();
61	        if ((config.username() != null) || (config.password() != null)) {
62	            String credDb = (config.credDb() == null) ? connectionString.getDatabase() : config.credDb();
63	
64	            MongoCredential credentials = MongoCredential.createCredential(
65	                    config.username(),
66	                    requireNonNull(credDb),
67	                    config.password().toCharArray());
68	
69	            settingsBuilder.credential(credentials);
70	        }
71	
72	        this.client = MongoClients.create(settingsBuilder.build());
73	        this.db = client.getDatabase(dbName != null ? dbName : "admin");
74	    }
75	
76	    /**
77	     * Creates an instance of MongoDB driver handler with MongoDb client and connection
78	     * supplied.
79	     * Used in jUnit tests to mock MongoDB driver internals.
80	     *
81	     * @param builder builder for mongoDB database
82	     * @param client  MongoDB client provided externally
