static String toJson(Object value) {
    if (value == null) {
        return JsonNull.instance().toString();
    }
    if (value instanceof JsonValue jsonValue) {
        return jsonValue.toString();
    }
    if (value instanceof Map<?, ?> map) {
        return toJsonObject(map);
    }
    if (value instanceof Iterable<?> iterable) {
        return toJsonArray(iterable);
    }
    if (value.getClass().isArray()) {
        return toJsonArray(value);
    }
    if ((value instanceof Integer) || (value instanceof Short) || (value instanceof Byte)) {
        return JsonNumber.create(((Number) value).longValue()).toString();
    }
    if (value instanceof Long longValue) {
        return JsonNumber.create(longValue).toString();
    }
    if ((value instanceof Double) || (value instanceof Float)) {
        return JsonNumber.create(((Number) value).doubleValue()).toString();
    }
    if (value instanceof BigInteger) {
        return value.toString();
    }
    if (value instanceof BigDecimal) {
        return value.toString();
    }
    if (value instanceof Boolean) {
        return value.toString();
    }
    // Check instanceof Number is more expensive than final types, it shall be at the end
    if (value instanceof Number) {
        return value.toString();
    }
    return JsonString.create(String.valueOf(value)).toString();
}

private static String toJsonObject(Map<?, ?> map) {
    StringBuilder result = new StringBuilder("{");
    Iterator<? extends Map.Entry<?, ?>> iterator = map.entrySet().iterator();
    while (iterator.hasNext()) {
        Map.Entry<?, ?> entry = iterator.next();
        result.append(JsonString.create(String.valueOf(entry.getKey())));
        result.append(':');
        result.append(toJson(entry.getValue()));
        if (iterator.hasNext()) {
            result.append(',');
        }
    }
    return result.append('}').toString();
}

private static String toJsonArray(Iterable<?> iterable) {
    StringBuilder result = new StringBuilder("[");
    Iterator<?> iterator = iterable.iterator();
    while (iterator.hasNext()) {
        result.append(toJson(iterator.next()));
        if (iterator.hasNext()) {
            result.append(',');
        }
    }
    return result.append(']').toString();
}

private static String toJsonArray(Object array) {
    StringBuilder result = new StringBuilder("[");
    int size = Array.getLength(array);
    for (int i = 0; i < size; i++) {
        result.append(toJson(Array.get(array, i)));
        if (i + 1 < size) {
            result.append(',');
        }
    }
    return result.append(']').toString();
}

